const d = $input.first().json;
const ts = new Date().toISOString();

let products = [];
try {
  products = typeof d.products === 'string' ? JSON.parse(d.products || '[]') : (d.products || []);
} catch(e) {}

const jsonOutput = {
  export_metadata: { exported_at: ts, format: 'json', version: '1.0' },
  run: { id: d.run_id, company_domain: d.company_domain },
  company: {
    name: d.company_name, domain: d.company_domain,
    description: d.description, founded_year: d.founded_year,
    employees: d.employees, headquarters: d.headquarters,
    website: d.website, logo_url: d.logo_url
  },
  score_card: {
    total_score: Number(d.score), confidence: d.confidence,
    report_url: d.report_url,
    pillars: [
      { name: 'Product', score: Number(d.product_score) },
      { name: 'ICP Fit', score: Number(d.icp_score) },
      { name: 'Team', score: Number(d.team_score) },
      { name: 'Business Model', score: Number(d.business_model_score) },
      { name: 'Funding', score: Number(d.funding_score) },
      { name: 'Growth', score: Number(d.growth_score) },
      { name: 'Market', score: Number(d.market_score) },
      { name: 'Risk', score: Number(d.risk_score) }
    ],
    composite: Number(d.score)
  },
  ai_extraction: {
    product_summary: d.product_summary, icp_analysis: d.icp_analysis,
    team_analysis: d.team_analysis, funding_summary: d.funding_summary,
    growth_indicators: d.growth_indicators, market_analysis: d.market_analysis,
    risk_factors: d.risk_factors, products
  }
};

return [{
  run_id: d.run_id,
  company_domain: d.company_domain,
  format: 'json',
  content: jsonOutput,
  company_name: d.company_name,
  score: d.score,
  confidence: d.confidence,
  product_score: d.product_score,
  icp_score: d.icp_score,
  funding_score: d.funding_score,
  growth_score: d.growth_score,
  report_url: d.report_url,
  risk_factors: d.risk_factors
}]

const d = $input.first().json;
const ts = new Date().toISOString();

const escape = (val) => {
  const s = String(val || '').replace(/"/g, '""');
  return s.includes(',') || s.includes('"') || s.includes('\n') ? `"${s}"` : s;
};

const header = 'run_id,company_domain,company_name,composite_score,product_score,icp_score,team_score,business_model_score,funding_score,growth_score,market_score,risk_score,confidence,description,founded_year,employees,headquarters,website,report_url,exported_at';
const row = [
  d.run_id, d.company_domain, d.company_name, d.score,
  d.product_score, d.icp_score, d.team_score, d.business_model_score,
  d.funding_score, d.growth_score, d.market_score, d.risk_score,
  d.confidence, d.description, d.founded_year, d.employees,
  d.headquarters, d.website, d.report_url, ts
].map(escape).join(',');

const csvContent = header + '\n' + row;

return [{
  run_id: d.run_id,
  company_domain: d.company_domain,
  format: 'csv',
  content: csvContent,
  company_name: d.company_name,
  score: d.score,
  confidence: d.confidence,
  product_score: d.product_score,
  icp_score: d.icp_score,
  funding_score: d.funding_score,
  growth_score: d.growth_score,
  report_url: d.report_url,
  risk_factors: d.risk_factors
}]
